const body = $json.body || {};
return [{ json: {
  titulo:     body.titulo     || 'Não informado',
  problema:   body.problema   || body.descricao || 'Não informado',
  descricao:  body.descricao  || '',
  user:       body.user       || '',
  parecer_id: body.parecer_id || ''
}}];

var r = $input.first().json;
var txt = r.text || r.output || (r.content && r.content[0] && r.content[0].text) || JSON.stringify(r);

var q = { termos: [], query_ilike: 'contrato', confidence: 0.5, domain: '' };
var s = txt.indexOf('{'); var e = txt.lastIndexOf('}');
if (s > -1 && e > s) { try { q = JSON.parse(txt.slice(s, e+1)); } catch(err) {} }

// Remove aspas ou apóstrofos que a IA teima em gerar para o FTS não quebrar
var query_clean = (q.query_ilike || 'contrato');
query_clean = query_clean.replace(/["']/g, '');

var wb = $('Normalizar Input').first().json;
return [{ json: {
  query_ilike: query_clean,
  termos:      q.termos      || [],
  confidence:  q.confidence  || 0.5,
  domain:      q.domain      || '',
  titulo:      wb.titulo,
  problema:    wb.problema,
  descricao:   wb.descricao,
  user:        wb.user,
  parecer_id:  wb.parecer_id
}}];

var resultados = $input.all();
var qn = $('Formatar Query').first().json;
var docs = [];
if (resultados && resultados.length > 0) {
  if (resultados.length === 1 && Array.isArray(resultados[0].json)) {
    docs = resultados[0].json;
  } else {
    docs = resultados.map(item => item.json).filter(doc => Object.keys(doc).length > 0);
  }
}

function stripHtml(html) {
  if (!html) return '';
  return html.replace(/<[^>]*>?/gm, ' ').replace(/\s+/g, ' ').trim();
}

// ─── Filtro de consistência temporal ─────────────────────────────────────────
// Exclui documentos com citações anacrónicas (ex: acórdão de 2008 citando lei de 2021)
function isTemporallyConsistent(doc) {
  var dataPub = doc.data_pub || '';
  var ano = dataPub ? parseInt(dataPub.substring(0, 4)) : null;
  var texto = (doc.ementa || '') + ' ' + (doc.excerto || '') + ' ' + (doc.snippet || '');

  if (ano && ano < 2021 && texto.includes('14.133')) {
    return false; // acórdão anterior a 2021 não pode citar Lei 14.133/2021
  }
  if (ano && ano < 1993 && texto.includes('8.666')) {
    return false; // acórdão anterior a 1993 não pode citar Lei 8.666/1993
  }
  return true;
}

var docsFiltrados = docs.filter(isTemporallyConsistent);
var removidos = docs.length - docsFiltrados.length;

var contexto = docsFiltrados.slice(0, 12).map(function(doc, i) {
  var citacao     = doc.citacao      || 'Precedente TCU';
  var temConteudo = doc.tem_conteudo;
  var ementa      = stripHtml(doc.ementa  || '').substring(0, 500);
  var snippet     = stripHtml(doc.snippet || '').substring(0, 400);
  var excerto     = stripHtml(doc.excerto || '').substring(0, 400);
  var conteudo    = excerto || ementa || snippet || '';

  var res = '[' + (i+1) + '] ' + citacao + '\n';

  if (!temConteudo || conteudo.length < 30) {
    res += '⚠️ SEM CONTEÚDO DISPONÍVEL NA BASE — NÃO CITAR ESTE DOCUMENTO\n';
  } else {
    res += 'Conteúdo: ' + conteudo + '\n';
    if (snippet && snippet.trim() !== ementa.trim() && snippet.length > 30) {
      res += 'Trecho relevante: ' + snippet;
    }
  }
  return res;
}).join('\n\n---\n\n');

return [{ json: {
  problema:                qn.problema,
  titulo:                  qn.titulo,
  descricao:               qn.descricao,
  user:                    qn.user,
  parecer_id:              qn.parecer_id,
  termos_buscados:         qn.termos,
  total_encontrado:        docs.length,
  filtrados_temporalmente: removidos,
  contexto_jurisprudencia: contexto
}}];

var r = $input.first().json;
var parecer = r.text || r.output || (r.content && r.content[0] && r.content[0].text) || JSON.stringify(r);
return [{ json: { output: parecer } }];
